# ── Agenda slide ──────────────────────────────────────────────────────────────
def _agenda_slide(slides_list: list):
    """slides_list = [{"name":..., "category":..., "icon":...}, ...]"""
    logo_uri = _logo_uri("dark")
    logo_html = f'<img src="{logo_uri}" alt="EMC" style="height:42px;object-fit:contain;">' if logo_uri else ""

    from collections import OrderedDict
    groups = OrderedDict()
    for s in slides_list:
        cat = s.get("category","Other")
        if cat not in groups: groups[cat] = []
        groups[cat].append(s)

    # Build numbered agenda items
    all_items = []
    num = 1
    for cat, slides in groups.items():
        all_items.append(("cat", cat))
        for s in slides:
            all_items.append(("slide", s["name"], num))
            num += 1

    half = (len([x for x in all_items if x[0]=="slide"]) + 1) // 2
    
    # Build two columns of items
    left_html = ""; right_html = ""; count = 0; in_right = False
    for item in all_items:
        if item[0] == "cat":
            cat_html = f'<div style="font-size:18px;font-weight:800;color:{CYAN};letter-spacing:.1em;text-transform:uppercase;margin-top:16px;margin-bottom:6px;padding-bottom:3px;border-bottom:1.5px solid {CYAN};">{item[1]}</div>'
            if not in_right: left_html  += cat_html
            else:             right_html += cat_html
        else:
            _, name, n = item
            row = f'<div style="display:flex;align-items:baseline;gap:10px;padding:5px 0;border-bottom:1px solid rgba(255,255,255,.08);"><span style="font-size:17px;font-weight:800;color:{RED};width:20px;flex-shrink:0;">{n}</span><span style="font-size:17px;color:rgba(255,255,255,.9);">{name}</span></div>'
            if count < half:
                left_html += row
            else:
                in_right = True
                right_html += row
            count += 1

    cols_html = f'''
    <div style="flex:1;padding-right:32px;">{left_html}</div>
    <div style="width:1px;background:rgba(255,255,255,.15);flex-shrink:0;"></div>
    <div style="flex:1;padding-left:32px;">{right_html}</div>'''

    return f"""
    <div style="position:absolute;top:0;left:0;right:0;bottom:0;background:{NAVY};">
      <div style="position:absolute;top:0;left:0;right:0;height:4px;background:{RED};"></div>
      <div style="position:absolute;bottom:0;left:0;right:0;height:4px;background:{RED};"></div>
      <div style="position:absolute;top:0;left:0;right:0;bottom:0;padding:44px 56px 60px;display:flex;flex-direction:column;">
        <!-- Header -->
        <div style="margin-bottom:8px;flex-shrink:0;">
          <div style="font-size:17px;font-weight:800;color:{CYAN};letter-spacing:.12em;margin-bottom:8px;">TODAY'S AGENDA</div>
          <div style="font-size:44px;font-weight:900;color:white;font-family:Calibri,Arial,sans-serif;">Presentation Overview</div>
        </div>
        <div style="height:2px;background:linear-gradient(to right,{RED},{CYAN},transparent);margin-bottom:32px;flex-shrink:0;"></div>
        <!-- Slide list columns — fills remaining space -->
        <div style="display:flex;gap:32px;flex-wrap:wrap;flex:1;align-content:flex-start;">
          {cols_html}
        </div>
      </div>
      <div style="position:absolute;bottom:16px;left:40px;">{logo_html}</div>
    </div>"""

