# ── District Profile slide ────────────────────────────────────────────────────
def _district_profile_slide(slide_data, chart_data, insights, month, year, source, footnote):
    district = slide_data.get("District","District")
    cats     = chart_data.get("categories", [])
    series   = chart_data.get("series", [])
    logo_uri = _logo_uri("light")
    logo_html= f'<img src="{logo_uri}" alt="EMC" style="height:32px;object-fit:contain;">' if logo_uri else ""
    date_str = f"{month} {year}".strip().upper()

    # Blue scale — no yellow
    COLORS_BAR = ["#93C5FD", "#1D4ED8", "#0D1B4B"]   # light-blue → medium-blue → dark-navy

    def mini_chart(metric):
        vals  = metric["values"]
        label = metric["name"]
        max_v = max((v for v in vals if v > 0), default=1) * 1.12
        W, H  = 240, 480
        pad_l, pad_r, pad_t, pad_b = 28, 12, 30, 56
        cw  = W - pad_l - pad_r
        ch  = H - pad_t - pad_b
        n   = len(cats)
        bw  = min(40, cw / n * 0.55)
        sp  = cw / n

        bars = ""
        for ci, (cat, val) in enumerate(zip(cats, vals)):
            cx  = pad_l + ci * sp + sp / 2
            bh  = (val / max_v) * ch if max_v else 0
            y   = pad_t + ch - bh
            c   = COLORS_BAR[ci % len(COLORS_BAR)]
            bars += f'<rect x="{cx-bw/2:.1f}" y="{y:.1f}" width="{bw:.1f}" height="{bh:.1f}" fill="{c}" rx="2.5"/>'
            # Choose text color based on bar brightness
            txt_color = "white" if ci >= 1 else "#1E3A8A"
            if bh > 22 and val > 0:
                bars += f'<text x="{cx:.1f}" y="{y+bh/2+5:.1f}" text-anchor="middle" font-size="13" font-weight="800" fill="{txt_color}">{val:.1f}%</text>'
            elif val > 0:
                bars += f'<text x="{cx:.1f}" y="{y-5:.1f}" text-anchor="middle" font-size="12" font-weight="700" fill="{DARK_TEXT}">{val:.1f}%</text>'
            bars += f'<text x="{cx:.1f}" y="{pad_t+ch+18}" text-anchor="middle" font-size="12" font-weight="600" fill="{DARK_TEXT}">{cat}</text>'

        return f"""
        <div style="flex:1;border-right:3px solid #9CA3AF;padding:10px 10px 0;display:flex;flex-direction:column;align-items:center;">
          <div style="font-size:13px;font-weight:800;color:{NAVY};text-align:center;line-height:1.25;margin-bottom:8px;min-height:32px;display:flex;align-items:center;justify-content:center;">{label}</div>
          <svg viewBox="0 0 {W} {H}" style="width:100%;flex:1;" preserveAspectRatio="xMidYMid meet">
            {bars}
            <line x1="{pad_l}" y1="{pad_t+ch}" x2="{W-pad_r}" y2="{pad_t+ch}" stroke="#9CA3AF" stroke-width="2"/>
          </svg>
        </div>"""

    metrics_html = "".join(mini_chart(s) for s in series)

    # Color legend
    legend_html = "".join(
        f'<div style="display:flex;align-items:center;gap:5px;font-size:11px;color:{DARK_TEXT};">'
        f'<div style="width:14px;height:14px;background:{COLORS_BAR[ci % len(COLORS_BAR)]};border-radius:2px;"></div>{cat}</div>'
        for ci, cat in enumerate(cats)
    )

    return f"""
    <div style="position:absolute;top:0;left:0;right:0;height:5px;background:{NAVY};"></div>
    <div style="position:absolute;top:0;left:0;right:0;bottom:0;padding:18px 26px 56px;display:flex;flex-direction:column;">
      <!-- Header -->
      <div style="display:flex;align-items:flex-start;justify-content:space-between;margin-bottom:8px;flex-shrink:0;">
        <div>
          <div style="font-size:26px;font-weight:900;color:{NAVY};font-family:Calibri,Arial,sans-serif;">Economic Mobility Center District Profile</div>
          <div style="font-size:16px;font-weight:700;color:{CYAN};text-transform:uppercase;">{district}</div>
        </div>
        <div style="font-size:13px;color:#6B7280;text-align:right;margin-top:4px;">{date_str}</div>
      </div>
      <div style="height:1.5px;background:linear-gradient(to right,{NAVY},{CYAN},transparent);margin-bottom:8px;flex-shrink:0;"></div>
      <!-- Color legend -->
      <div style="display:flex;gap:20px;margin-bottom:10px;flex-shrink:0;">{legend_html}</div>
      <!-- 5 metric columns -->
      <div style="display:flex;border:3px solid #9CA3AF;border-radius:8px;overflow:hidden;flex:1;min-height:0;">
        {metrics_html}
      </div>
    </div>
    <div style="position:absolute;bottom:10px;left:26px;right:26px;display:flex;align-items:center;justify-content:space-between;">
      {logo_html}
      <div style="font-size:11px;color:{MID_GRAY};max-width:860px;">{footnote or source}</div>
    </div>"""

# ── CCMR Pathway Full slide ───────────────────────────────────────────────────
def _ccmr_pathway_full_slide(slide_data, chart_data, insights, month, year, source, footnote):
    district = slide_data.get("District","District")
    cats = chart_data.get("categories", [])
    series = chart_data.get("series", [])
    logo_uri = _logo_uri("light")
    logo_html= f'<img src="{logo_uri}" alt="EMC" style="height:36px;object-fit:contain;">' if logo_uri else ""
    values = series[0]["values"] if series else []
    date_str = f"{month} {year}".strip()

    # Color bars by value: top=dark navy, mid=cyan, low=light gray
    def bar_color(val, max_v):
        pct = val/max_v if max_v else 0
        if pct >= 0.6: return NAVY
        if pct >= 0.3: return CYAN
        return "#9CA3AF"

    max_v = max(values) if values else 1
    W, H  = 680, 520
    lbl_w = 170
    pad_r, pad_t, pad_b = 60, 10, 24
    cw    = W - lbl_w - pad_r
    ch    = H - pad_t - pad_b
    n     = len(cats)
    bar_h = min(26, max(12, ch // max(n, 1) - 5))
    gap   = max(3, (ch - bar_h * n) / (n + 1)) if n > 0 else 8

    grid = "".join(
        f'<line x1="{lbl_w+(t/100)*cw:.1f}" y1="{pad_t}" x2="{lbl_w+(t/100)*cw:.1f}" y2="{pad_t+ch}" stroke="#E5E7EB" stroke-width="1"/>'
        f'<text x="{lbl_w+(t/100)*cw:.1f}" y="{H-6}" text-anchor="middle" font-size="9" fill="#9CA3AF">{t}%</text>'
        for t in [0, 20, 40, 60, 80, 100] if t <= max_v * 1.05
    ) + f'<text x="{lbl_w + cw/2:.0f}" y="{H-1}" text-anchor="middle" font-size="9" font-weight="700" fill="#374151">Percent of CCMR A-F Met Students (%)</text>'

    bars = ""
    for ci, (cat, val) in enumerate(zip(cats, values)):
        bw  = (val / max_v) * cw if max_v else 0
        y   = pad_t + gap + ci * (bar_h + gap)
        color = bar_color(val, max_v)
        bars += f'<text x="{lbl_w-6}" y="{y+bar_h/2+3:.1f}" text-anchor="end" font-size="10" fill="#1F2933">{cat}</text>'
        bars += f'<rect x="{lbl_w}" y="{y:.1f}" width="{max(bw,2):.1f}" height="{bar_h}" fill="{color}" rx="3"/>'
        bars += f'<text x="{lbl_w+max(bw,2)+4:.1f}" y="{y+bar_h/2+3:.1f}" font-size="9.5" font-weight="700" fill="#374151">{val:.1f}%</text>'

    chart_svg = f'<svg viewBox="0 0 {W} {H}" xmlns="http://www.w3.org/2000/svg" preserveAspectRatio="none" style="width:100%;height:100%;">{grid}<line x1="{lbl_w}" y1="{pad_t}" x2="{lbl_w}" y2="{pad_t+ch}" stroke="#D1D5DB"/>{bars}</svg>'

    # Right panel: insight callout + date/title
    ins_html = ""
    if insights:
        bullets = "".join(f'<div style="padding:4px 0;border-bottom:1px solid rgba(0,176,240,.15);font-size:11px;color:#1F2933;">&#9658; {i}</div>' for i in insights)
        ins_html = f'<div style="background:#EFF6FF;border-left:4px solid {CYAN};border-radius:4px;padding:8px 11px;margin-bottom:10px;"><div style="font-size:17px;font-weight:800;color:{NAVY};letter-spacing:.08em;margin-bottom:3px;">KEY INSIGHTS</div>{bullets}</div>'

    note = ("Among all students from the selected cohort, this chart shows how many met each CCMR qualifier. "
            "Students may qualify through multiple pathways, so totals are not mutually exclusive.")

    return f"""
    <div style="position:absolute;top:0;left:0;right:0;height:5px;background:{NAVY};"></div>
    <div style="position:absolute;top:0;left:0;right:0;bottom:0;padding:16px 24px 52px;display:flex;flex-direction:column;">
      <div style="display:flex;align-items:flex-start;justify-content:space-between;margin-bottom:8px;">
        <div>
          <div style="font-size:24px;font-weight:900;color:{NAVY};font-family:Calibri,Arial,sans-serif;">CCMR Pathway Analysis — All Qualifiers</div>
          <div style="font-size:17px;font-weight:700;color:{CYAN};">{district} &bull; {date_str}</div>
        </div>
        <div style="background:{RED};color:white;font-size:11px;font-weight:800;padding:4px 12px;border-radius:4px;font-style:italic;">CCMR PATHWAYS</div>
      </div>
      <div style="height:1.5px;background:linear-gradient(to right,{NAVY},{CYAN},transparent);margin-bottom:10px;"></div>
      <div style="display:flex;gap:16px;flex:1;min-height:0;">
        <div style="flex:1;min-width:0;">{chart_svg}</div>
        <div style="width:280px;display:flex;flex-direction:column;gap:0;">
          {ins_html}
          <div style="background:#F8FAFC;border:1px solid #E5E7EB;border-radius:6px;padding:10px 12px;font-size:10px;color:#6B7280;line-height:1.4;">{note}</div>
        </div>
      </div>
    </div>
    <div style="position:absolute;bottom:8px;left:24px;right:24px;display:flex;align-items:center;justify-content:space-between;">
      {logo_html}
      <div style="font-size:17px;color:#6B7280;">{footnote or source}</div>
    </div>"""


# ── HB3 Funds slide ───────────────────────────────────────────────────────────
def _hb3_funds_slide(slide_data, chart_data, insights, month, year, source, footnote):
    district  = slide_data.get("District","District")
    cats      = chart_data.get("categories", [])
    series    = chart_data.get("series", [])
    statuses  = chart_data.get("statuses", [])
    values    = series[0]["values"] if series else []
    total     = slide_data.get("total_funding","")
    yrs_cover = slide_data.get("years_covered","")
    logo_uri  = _logo_uri("light")
    logo_html = f'<img src="{logo_uri}" alt="EMC" style="height:36px;object-fit:contain;">' if logo_uri else ""
    date_str  = f"{month} {year}".strip()

    STATUS_COLORS = {"verified": "#0D1B4B", "estimate": "#2563EB", "projected": "#7DD3FC"}
    STATUS_LABELS = {"verified": "VERIFIED", "estimate": "ESTIMATE", "projected": "PROJECTED"}
    STATUS_DESC   = {
        "verified":  "TEA/Commit confirmed actuals",
        "estimate":  "CC Solutions preliminary",
        "projected": "Trend-based forecast",
    }
    STATUS_TAG_COLORS = {"verified": "#16A34A", "estimate": "#D97706", "projected": "#7C3AED"}

    # Bar chart SVG
    W, H = 680, 400
    pad_l, pad_b, pad_t, pad_r = 70, 80, 20, 20
    cw, ch = W-pad_l-pad_r, H-pad_t-pad_b
    max_v = max(values) * 1.15 if values and any(v>0 for v in values) else 1.0

    def fmt_m(v):
        """Format a value that may be raw dollars or already in millions."""
        if v >= 1_000_000: return f"${v/1_000_000:.1f}M"
        if v >= 1_000:     return f"${v/1_000:.1f}K"
        if v >= 1:         return f"${v:.1f}M"   # already in millions
        if v > 0:          return f"${v*1000:.0f}K"
        return "$0"
    def y_tick(v): return f"${v:.1f}M" if v >= 1 else f"${v*1000:.0f}K"

    grid = ""
    n_ticks = 4
    for k in range(n_ticks+1):
        t = max_v * k / n_ticks
        y = pad_t + ch - (t/max_v)*ch
        grid += f'<line x1="{pad_l}" y1="{y:.1f}" x2="{pad_l+cw}" y2="{y:.1f}" stroke="#E5E7EB" stroke-width="1"/>'
        grid += f'<text x="{pad_l-5}" y="{y+4:.1f}" text-anchor="end" font-size="9.5" fill="#9CA3AF">{y_tick(t)}</text>'

    n = len(cats); spacing = cw/n if n else cw; bw = min(70, spacing*0.55)
    bars = ""
    for ci, (cat, val) in enumerate(zip(cats, values)):
        st  = statuses[ci] if ci < len(statuses) else "estimate"
        c   = STATUS_COLORS.get(st, NAVY)
        bh  = (val/max_v)*ch if max_v else 0
        cx  = pad_l + ci*spacing + spacing/2
        y   = pad_t + ch - bh
        bars += f'<rect x="{cx-bw/2:.1f}" y="{y:.1f}" width="{bw:.1f}" height="{bh:.1f}" fill="{c}" rx="3"/>'
        if bh > 18:
            bars += f'<text x="{cx:.1f}" y="{y+bh/2+4:.1f}" text-anchor="middle" font-size="11" font-weight="700" fill="white">{fmt_m(val)}</text>'
        bars += f'<text x="{cx:.1f}" y="{pad_t+ch+14}" text-anchor="middle" font-size="11" font-weight="700" fill="#1F2933">{cat}</text>'
        bars += f'<text x="{cx:.1f}" y="{pad_t+ch+26}" text-anchor="middle" font-size="9" fill="#6B7280">{STATUS_LABELS.get(st,"")}</text>'

    chart_svg = f'<svg viewBox="0 0 {W} {H}" xmlns="http://www.w3.org/2000/svg" preserveAspectRatio="none" preserveAspectRatio="none" style="width:100%;height:100%;">{grid}<line x1="{pad_l}" y1="{pad_t}" x2="{pad_l}" y2="{pad_t+ch}" stroke="#D1D5DB"/><line x1="{pad_l}" y1="{pad_t+ch}" x2="{pad_l+cw}" y2="{pad_t+ch}" stroke="#D1D5DB"/>{bars}</svg>'

    # Right sidebar cards
    total_card = f"""<div style="background:{NAVY};border-radius:8px;padding:12px 14px;margin-bottom:10px;text-align:center;">
      <div style="font-size:8px;font-weight:800;color:{CYAN};letter-spacing:.1em;margin-bottom:4px;">{len(cats)}-YEAR HB3 FUNDS TOTAL</div>
      <div style="font-size:32px;font-weight:900;color:white;">{total}</div>
      <div style="font-size:18px;color:rgba(255,255,255,.7);">{district} · {yrs_cover}</div>
    </div>"""

    class_cards = ""
    for ci, (cat, val) in enumerate(zip(cats, values)):
        st   = statuses[ci] if ci < len(statuses) else "estimate"
        stc  = STATUS_TAG_COLORS.get(st,"#6B7280")
        class_cards += f"""<div style="background:#F9FAFB;border:1px solid #E5E7EB;border-left:4px solid {STATUS_COLORS.get(st,NAVY)};border-radius:4px;padding:8px 10px;margin-bottom:6px;">
          <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:2px;">
            <div style="font-size:17px;font-weight:800;color:#6B7280;letter-spacing:.06em;">{cat.upper()}</div>
            <span style="font-size:8px;font-weight:800;color:{stc};background:rgba(0,0,0,.05);padding:1px 6px;border-radius:8px;">{STATUS_LABELS.get(st,"")}</span>
          </div>
          <div style="font-size:24px;font-weight:900;color:{STATUS_COLORS.get(st,NAVY)};">{fmt_m(val)}</div>
        </div>"""

    status_key = ""  # Status key removed — statuses shown on bar labels directly

    return f"""
    <div style="position:absolute;top:0;left:0;right:0;height:5px;background:{NAVY};"></div>
    <div style="position:absolute;top:0;left:0;right:0;bottom:0;padding:16px 24px 52px;display:flex;flex-direction:column;">
      <!-- Header -->
      <div style="display:flex;align-items:flex-start;justify-content:space-between;margin-bottom:6px;">
        <div>
          <div style="font-size:18px;font-weight:800;color:{CYAN};letter-spacing:.08em;">CCMR OUTCOMES</div>
          <div style="font-size:30px;font-weight:900;color:{NAVY};font-family:Calibri,Arial,sans-serif;">HB3 Outcomes Bonus Funding</div>
          <div style="font-size:17px;font-weight:700;color:{CYAN};">{district}</div>
        </div>
      </div>
      <div style="height:1.5px;background:linear-gradient(to right,{NAVY},{CYAN},transparent);margin-bottom:10px;"></div>
      <!-- Chart + sidebar -->
      <div style="display:flex;gap:16px;flex:1;min-height:0;">
        <div style="flex:1;min-width:0;">
          <div style="font-size:17px;font-weight:800;color:#6B7280;letter-spacing:.06em;margin-bottom:4px;">HB3 FUNDS BY CLASS YEAR</div>
          {chart_svg}
        </div>
        <div style="width:240px;display:flex;flex-direction:column;overflow-y:auto;">
          {total_card}
          {class_cards}

        </div>
      </div>
    </div>
    <div style="position:absolute;bottom:8px;left:24px;right:24px;display:flex;align-items:center;justify-content:space-between;">
      {logo_html}
      <div style="font-size:17px;color:#6B7280;font-style:italic;">&#128197; {footnote or ("Data as of " + date_str)}</div>
    </div>"""


# ── "By the Numbers" slide ────────────────────────────────────────────────────
def _by_the_numbers_slide(slide_data, chart_data, insights, month, year, source, footnote):
    district  = slide_data.get("District", "District")
    cohort    = slide_data.get("Cohort", "")
    logo_uri  = _logo_uri("light")
    logo_html = f'<img src="{logo_uri}" alt="EMC" style="height:40px;object-fit:contain;">' if logo_uri else ""
    date_str  = f"{month} {year}".strip()

    cats   = chart_data.get("categories", ["Students","TSI Met","HB3 Projection"])
    series = chart_data.get("series", [])
    vals   = series[0]["values"] if series else [0, 0, 0]

    def fmt_num(n, prefix="", suffix=""):
        try:
            v = float(n)
            if v >= 1_000_000: return f"{prefix}{v/1_000_000:.1f}M{suffix}"
            if v >= 1_000:     return f"{prefix}{v/1_000:.0f}K{suffix}"
            return f"{prefix}{v:.0f}{suffix}"
        except: return str(n)

    # Icons per metric (SVG paths)
    ICONS = [
        # Person/ID card icon
        '<path d="M12 12c2.7 0 5-2.3 5-5s-2.3-5-5-5-5 2.3-5 5 2.3 5 5 5zm0 2c-3.3 0-10 1.7-10 5v2h20v-2c0-3.3-6.7-5-10-5z" fill="white"/>',
        # Pencil/check icon
        '<path d="M3 17.25V21h3.75L17.81 9.94l-3.75-3.75L3 17.25zM20.71 7.04c.39-.39.39-1.02 0-1.41l-2.34-2.34c-.39-.39-1.02-.39-1.41 0l-1.83 1.83 3.75 3.75 1.83-1.83z" fill="white"/>',
        # Dollar sign
        '<path d="M11.8 10.9c-2.27-.59-3-1.2-3-2.15 0-1.09 1.01-1.85 2.7-1.85 1.78 0 2.44.85 2.5 2.1h2.21c-.07-1.72-1.12-3.3-3.21-3.81V3h-3v2.16c-1.94.42-3.5 1.68-3.5 3.61 0 2.31 1.91 3.46 4.7 4.13 2.5.6 3 1.48 3 2.41 0 .69-.49 1.79-2.7 1.79-2.06 0-2.87-.92-2.98-2.1h-2.2c.12 2.19 1.76 3.42 3.68 3.83V21h3v-2.15c1.95-.37 3.5-1.5 3.5-3.55 0-2.84-2.43-3.81-4.7-4.4z" fill="white"/>',
    ]

    subtexts = chart_data.get("subtexts", ["","",""])

    def metric_circle(i, label, val, is_dollar=False):
        raw = val
        display = fmt_num(val, "$" if is_dollar else "")
        icon_path = ICONS[i % len(ICONS)]
        subtext = subtexts[i] if i < len(subtexts) else ""
        sub_html = f'<div style="font-size:18px;color:#4B5563;text-align:center;margin-top:8px;line-height:1.5;">{subtext}</div>' if subtext else ""

        return f"""
        <div style="display:flex;flex-direction:column;align-items:center;flex:1;">
          <!-- Circle -->
          <div style="position:relative;width:220px;height:220px;margin-bottom:20px;">
            <!-- Outer ring -->
            <svg viewBox="0 0 220 220" style="position:absolute;inset:0;width:220px;height:220px;">
              <circle cx="110" cy="110" r="105" fill="none" stroke="{CYAN}" stroke-width="6" stroke-dasharray="320 80" stroke-linecap="round"/>
            </svg>
            <!-- Inner filled circle -->
            <div style="position:absolute;top:10px;left:10px;width:200px;height:200px;background:{NAVY};border-radius:50%;display:flex;align-items:center;justify-content:center;">
              <div style="font-size:52px;font-weight:900;color:white;font-family:Calibri,Arial,sans-serif;">{display}</div>
            </div>
            <!-- Icon badge -->
            <div style="position:absolute;bottom:10px;{'right:10px' if i==2 else 'left:10px'};width:46px;height:46px;background:{RED};border-radius:50%;display:flex;align-items:center;justify-content:center;">
              <svg viewBox="0 0 24 24" width="24" height="24">{icon_path}</svg>
            </div>
          </div>
          <!-- Label -->
          <div style="font-size:18px;font-weight:800;color:{RED};text-align:center;line-height:1.2;margin-bottom:8px;">{label}</div>
          {sub_html}
        </div>"""

    circles_html = "".join(
        metric_circle(i, cats[i] if i < len(cats) else f"Metric {i+1}",
                      vals[i] if i < len(vals) else 0,
                      is_dollar=(i == 2))
        for i in range(min(3, len(cats)))
    )

    header_sub = f'<div style="font-size:17px;font-weight:700;color:{RED};text-align:center;margin-bottom:4px;">{district}{" – " + cohort if cohort else ""}</div>' if district else ""

    return f"""
    <div style="position:absolute;top:0;left:0;right:0;height:5px;background:{NAVY};"></div>
    <div style="position:absolute;top:0;left:0;right:0;bottom:0;padding:20px 48px 56px;display:flex;flex-direction:column;align-items:center;">
      {header_sub}
      <div style="font-size:44px;font-weight:900;color:{NAVY};text-align:center;font-family:Calibri,Arial,sans-serif;margin-bottom:24px;">By The Numbers</div>
      <div style="width:100%;height:1.5px;background:linear-gradient(to right,transparent,{NAVY},{CYAN},transparent);margin-bottom:32px;"></div>
      <!-- Three metric circles -->
      <div style="display:flex;gap:32px;justify-content:center;align-items:flex-start;flex:1;">
        {circles_html}
      </div>
    </div>
    <div style="position:absolute;bottom:10px;left:40px;right:40px;display:flex;align-items:center;justify-content:space-between;">
      {logo_html}
      <div style="font-size:17px;color:#6B7280;">{footnote or source}</div>
    </div>"""


# ── Outro / Thank You slide ───────────────────────────────────────────────────
def _outro_slide(slide_data):
    district = slide_data.get("District","")
    logo_uri = _logo_uri("dark")
    return f"""
    <div style="position:absolute;top:0;left:0;right:0;bottom:0;background:{NAVY};">
      <div style="position:absolute;top:0;left:0;right:0;height:4px;background:{RED};"></div>
      <div style="position:absolute;bottom:0;left:0;right:0;height:4px;background:{RED};"></div>
      <!-- Background decorative circles -->
      <svg style="position:absolute;inset:0;width:100%;height:100%;opacity:.12;" viewBox="0 0 1333 750" preserveAspectRatio="xMidYMid slice">
        <circle cx="200" cy="375" r="400" fill="none" stroke="{CYAN}" stroke-width="80"/>
        <circle cx="1133" cy="375" r="400" fill="none" stroke="{CYAN}" stroke-width="80"/>
        <circle cx="666" cy="375" r="260" fill="none" stroke="{RED}" stroke-width="50"/>
      </svg>
      <!-- Content -->
      <div style="position:absolute;inset:0;display:flex;flex-direction:column;align-items:center;justify-content:center;gap:16px;padding:60px;">
        <div style="font-size:17px;font-weight:800;color:{CYAN};letter-spacing:.14em;text-transform:uppercase;">Economic Mobility Center</div>
        <div style="font-size:72px;font-weight:900;color:white;text-align:center;font-family:Calibri,Arial,sans-serif;line-height:1.0;">Thank You</div>
        <div style="height:3px;width:120px;background:{RED};border-radius:2px;"></div>
        {f'<div style="font-size:20px;color:rgba(255,255,255,.75);text-align:center;margin-top:4px;">{district}</div>' if district else ""}
        <div style="font-size:18px;color:rgba(255,255,255,.55);text-align:center;margin-top:8px;font-style:italic;">
          Every Learner On A Path To A Living Wage
        </div>
      </div>
      <!-- Logo bottom center -->
      <div style="position:absolute;bottom:24px;left:50%;transform:translateX(-50%);">
        <img src="{logo_uri}" alt="EMC" style="height:46px;object-fit:contain;"/>
      </div>
    </div>"""

